import{_ as a,o as t,c as r,ae as i}from"./chunks/framework.CRIdhvba.js";const b=JSON.parse('{"title":"分布式与高可用数据库 · 第 1 章 复制与读写分离","description":"","frontmatter":{"title":"分布式与高可用数据库 · 第 1 章 复制与读写分离"},"headers":[],"relativePath":"career/backend/db-dev/distributed-db/index.md","filePath":"career/backend/db-dev/distributed-db/index.md"}'),d={name:"career/backend/db-dev/distributed-db/index.md"};function n(o,e,l,s,c,_){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="分布式与高可用数据库-·-第-1-章-复制与读写分离" tabindex="-1">分布式与高可用数据库 · 第 1 章 复制与读写分离 <a class="header-anchor" href="#分布式与高可用数据库-·-第-1-章-复制与读写分离" aria-label="Permalink to &quot;分布式与高可用数据库 · 第 1 章 复制与读写分离&quot;">​</a></h1><p>当单机数据库无法满足容量或可用性需求时，你就需要考虑「复制」「读写分离」甚至「分库分表」等方案。</p><p>本章先从最经典的 <strong>主从复制 + 读写分离</strong> 讲起。</p><h2 id="_1-1-主从复制的基本模型" tabindex="-1">1.1 主从复制的基本模型 <a class="header-anchor" href="#_1-1-主从复制的基本模型" aria-label="Permalink to &quot;1.1 主从复制的基本模型&quot;">​</a></h2><p>以 MySQL 为例，主从复制大致分为：</p><ol><li>主库将变更记录到二进制日志（binlog）；</li><li>从库拉取 binlog 并写入中继日志（relay log）；</li><li>从库重放中继日志，将变更应用到本地数据；</li><li>上层通过读写分离中间件，将写请求打到主库、读请求打到从库。</li></ol><p>理解这一过程有助于你在延迟、数据不一致、复制错误时快速定位问题。</p>',7)])])}const h=a(d,[["render",n]]);export{b as __pageData,h as default};
